+RmsNormQuantizationPlugin::RmsNormQuantizationPlugin(const void* data, size_t length)
+{
+    const char *d = reinterpret_cast<const char*>(data), *a = d;
+    read(d, mEps);
+    read(d, mDynActScaling);
+    read(d, mType);
